module RefModule (
    input clk,
    input reset,
    output reg [1:0] count
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 2'b00;
        end else begin
            count <= count + 1;
        end
    end
endmodule
